mapper.select:
select id, name, description, created_at, created_by
from app_roles
where id = #{roleId}

mapper.update:
update app_roles
set name = #{name},
    description = #{description}
where id = #{id}

mapper.select:
select id, username, password, grade, created_at
from app_users
where username = #{username}

select id, username, password, grade, created_at
from app_users
where id = #{userId}

mapper.update:
update app_users
set password = #{password}
where id = #{id}

mapper.select:
select u.id, u.username, u.password, u.grade, u.created_at from app_users u join app_user_profiles p on p.user_id = u.id where lower(p.full_name) = lower(#{fullName}) and lower(p.email) = lower(#{email})
and p.birth_date = #{birthDate}
limit 1

select u.id, u.username, u.password, u.grade, u.created_at from app_users u join app_user_profiles p on p.user_id = u.id where lower(p.full_name) = lower(#{fullName}) and p.phone_number = #{phoneNumber}
and p.birth_date = #{birthDate}
limit 1

select count(*)
from app_user_role_assignments
where tenant_id = #{tenantId}
